// // This module compares two 4-bit inputs, A and B, and generates two outputs: EQ (signals when A is not equal to B), and GT (indicates when A is less than or equal to B).
module top_module(
    input [3:0] A,
    input [3:0] B,
    output EQ,
    output GT
    );assign EQ = (A == B);
    assign GT = (A > B);

endmodule
